const n=(r,t="so'm")=>{if(!r&&r!==0)return`0 ${t}`;const e=Number(r);return isNaN(e)?`0 ${t}`:new Intl.NumberFormat("uz-UZ").format(e)+` ${t}`},o=(r,t="so'm")=>{if(!r&&r!==0)return`0 ${t}`;const e=Number(r);return isNaN(e)?`0 ${t}`:e>=1e9?(e/1e9).toFixed(1)+`B ${t}`:e>=1e6?(e/1e6).toFixed(1)+`M ${t}`:e>=1e3?(e/1e3).toFixed(0)+`K ${t}`:new Intl.NumberFormat("uz-UZ").format(e)+` ${t}`},f=r=>{if(!r&&r!==0)return"0";const t=Number(r);return isNaN(t)?"0":new Intl.NumberFormat("uz-UZ").format(t)},i=(r,t=1)=>{if(!r&&r!==0)return"0%";const e=Number(r);return isNaN(e)?"0%":e.toFixed(t)+"%"};export{o as a,n as b,i as c,f};
